#include <bits/stdc++.h>
using namespace std;

const int N=55,P=1e9+7;

int n,m,h[N],f[N][N],g[N][N][N],mi[N*N],C[N][N];

int main(){
    scanf("%d%d",&n,&m);
    mi[0]=1;
    for(int i=1;i<=n*n;i++)
        mi[i]=2*mi[i-1]%P;
    for(int i=0;i<=n;i++)
        for(int j=0;j<=i;j++)
            C[i][j]=(j==0 || j==i?1:C[i-1][j-1]+C[i-1][j])%P;
    for(int i=1;i<=n;i++){
        h[i]=mi[i*(i-1)/2];
        for(int j=1;j<i;j++)
            h[i]=(h[i]-1ll*mi[(i-j)*(i-j-1)/2]*C[i-1][j-1]%P*h[j])%P;
        h[i]=(h[i]+P)%P;
        //printf("%d ",h[i]);
    }
    //puts("");
    for(int i=1;i<=n;i++){
        f[i][0]=h[i];
        for(int j=1;j<i;j++){
            for(int p=1;p<=i-j;p++)
                for(int q=1,pr=p;q<=j;q++,pr=1ll*pr*p%P)
                    f[i][j]=(f[i][j]+1ll*C[i-1][p-1]*pr%P*g[i-p][q][j-q]%P*f[p][0])%P;
            f[i][0]=(f[i][0]-f[i][j]+P)%P;
        }
        for(int j=1;j<=i;j++)
            for(int k=0;k<=i-j;k++){
                if(j==1){
                    g[i][j][k]=1ll*f[i][k]*i%P;
                    continue;
                }
                for(int p=1;p<=i-j+1;p++)
                    for(int q=0;q<=k;q++)
                        g[i][j][k]=(g[i][j][k]+1ll*C[i-1][p-1]*p%P*f[p][q]%P*g[i-p][j-1][k-q])%P;
            }
    }
    int ans=0;
    m=min(m,n-1);
    for(int i=0;i<=m;i++)
        ans=(ans+f[n][i])%P;
    printf("%d",ans);
    return 0;
}
